const { db, redis } = require('../config/database');

class UserPixelState {
  static tableName = 'user_pixel_states';

  // 获取或创建用户状态
  static async getOrCreate(userId) {
    try {
      console.log('获取或创建用户状态，用户ID:', userId);
      let state = await this.findByUserId(userId);
      
      if (!state) {
        console.log('用户状态不存在，开始创建...');
        
        // 对于游客用户，直接创建状态记录
        if (userId.startsWith('guest_')) {
          console.log('创建游客用户状态记录...');
          const [newState] = await db(this.tableName)
            .insert({
              user_id: userId,
              pixel_points: 64,
              last_accum_time: Math.floor(Date.now() / 1000),
              freeze_until: 0
            })
            .returning('*');
          
          state = newState;
          console.log('游客用户状态创建成功:', state);
          await this.setCache(userId, state);
        } else {
          // 对于注册用户，检查用户是否存在
          const user = await db('users').where({ id: userId }).first();
          if (!user) {
            console.log('用户不存在，无法创建状态');
            throw new Error('用户不存在');
          }
          
          console.log('创建注册用户状态记录...');
          const [newState] = await db(this.tableName)
            .insert({
              user_id: userId,
              pixel_points: 64,
              last_accum_time: Math.floor(Date.now() / 1000),
              freeze_until: 0
            })
            .returning('*');
          
          state = newState;
          console.log('注册用户状态创建成功:', state);
          await this.setCache(userId, state);
        }
      } else {
        console.log('找到现有用户状态:', state);
      }
      
      return state;
    } catch (error) {
      console.error('获取或创建用户状态时发生错误:', error);
      console.error('错误堆栈:', error.stack);
      throw error;
    }
  }

  // 根据用户ID查找状态
  static async findByUserId(userId) {
    const cached = await this.getCache(userId);
    if (cached) return cached;
    
    const state = await db(this.tableName)
      .where({ user_id: userId })
      .first();
    
    if (state) {
      await this.setCache(userId, state);
    }
    
    return state;
  }

  // 更新用户状态
  static async update(userId, updates) {
    const [updatedState] = await db(this.tableName)
      .where({ user_id: userId })
      .update({
        ...updates,
        updated_at: db.fn.now()
      })
      .returning('*');
    
    if (updatedState) {
      await this.setCache(userId, updatedState);
    }
    
    return updatedState;
  }

  // 消耗点数
  static async consumePoint(userId) {
    try {
      console.log('开始消耗点数，用户ID:', userId);
      const state = await this.getOrCreate(userId);
      console.log('获取到用户状态:', state);
      
      const now = Math.floor(Date.now() / 1000);
      
      if (state.freeze_until > 0) {
        console.log('用户处于冻结状态，freeze_until:', state.freeze_until, '当前时间:', now);
        if (now >= state.freeze_until) {
          console.log('冻结状态已过期，恢复1点');
          return await this.update(userId, {
            pixel_points: 1,
            last_accum_time: now,
            freeze_until: 0
          });
        }
        console.log('仍在冻结中，无法消耗点数');
        return null;
      }
      
      if (state.pixel_points > 0) {
        const newPoints = state.pixel_points - 1;
        const freezeUntil = newPoints === 0 ? now + 10 : 0;
        
        console.log('消耗1点，剩余点数:', newPoints, '冻结时间:', freezeUntil);
        return await this.update(userId, {
          pixel_points: newPoints,
          freeze_until: freezeUntil
        });
      }
      
      console.log('用户点数不足');
      return null;
    } catch (error) {
      console.error('消耗点数时发生错误:', error);
      console.error('错误堆栈:', error.stack);
      throw error;
    }
  }

  // 缓存方法
  static async setCache(userId, state) {
    try {
      await redis.setEx(`user_state:${userId}`, 300, JSON.stringify(state));
    } catch (error) {
      console.error('设置用户状态缓存失败:', error);
    }
  }

  static async getCache(userId) {
    try {
      const cached = await redis.get(`user_state:${userId}`);
      return cached ? JSON.parse(cached) : null;
    } catch (error) {
      console.error('获取用户状态缓存失败:', error);
      return null;
    }
  }
}

module.exports = UserPixelState;
